+    if (m_calibGear < 0) return 0.0f;
+
+    const int n = static_cast<int>(m_capture.v.size());
+    if (n == 0) return 0.0f;
+
+    // Inlier progress: fraction toward N_min.
+    float inlierProg = std::min(1.0f, static_cast<float>(n) / static_cast<float>(RANSAC_N_MIN));
